     1→import React, { useState, useEffect } from 'react';
     2→import Card from './Card';
     3→import { Settings, RefreshCw, Trash2, Users } from 'lucide-react';
     4→import { resetDatabase, emptyDatabase } from '../firebase/dbActions';
     5→import { getAuth } from 'firebase/auth';
     6→import { auth } from '../firebase/config';
     7→import { useAuth } from '../hooks/useAuth'; // Import useAuth hook
     8→
     9→export default function AdminPanel() {
    10→  const [tableCount, setTableCount] = useState(4);
    11→  const [isUpdating, setIsUpdating] = useState(false);
    12→  const [isEmptying, setIsEmptying] = useState(false);
    13→  const [isClearingAnonymousUsers, setIsClearingAnonymousUsers] = useState(false);
    14→  const [users, setUsers] = useState([]);
    15→  const { getAllUsers, updateUserRole, registerUser, deleteUser, changeUserPassword } = useAuth();
    16→  const [newUserEmail, setNewUserEmail] = useState('');
    17→  const [newUserPassword, setNewUserPassword] = useState('');
    18→
    19→  useEffect(() => {
    20→    const fetchUsers = async () => {
    21→      const userList = await getAllUsers();
    22→      setUsers(userList);
    23→    };
    24→    fetchUsers();
    25→  }, [getAllUsers]);
    26→
    27→  const cloudFunctionsBaseUrl = `https://us-central1-${import.meta.env.VITE_FIREBASE_PROJECT_ID}.cloudfunctions.net`;
    28→  // ... (rest of the component)
    29→
    30→
    31→  const handleReset = async () => {
    32→    setIsUpdating(true);
    33→    try {
    34→      await resetDatabase(tableCount);
    35→    } catch {
    36→      alert("Erreur lors de la mise à jour");
    37→    } finally {
    38→      setIsUpdating(false);
    39→    }
    40→  };
    41→
    42→  const handleEmpty = async () => {
    43→    if (!confirm("Êtes-vous sûr de vouloir vider complètement la base de données ? Cette action est irréversible.")) {
    44→      return;
    45→    }
    46→    setIsEmptying(true);
    47→    try {
    48→      await emptyDatabase();
    49→      alert("Base de données vidée avec succès.");
    50→    } catch {
    51→      alert("Erreur lors du vidage de la base de données");
    52→    }
    53→    finally {
    54→      setIsEmptying(false);
    55→    }
    56→  };
    57→
    58→  const handleRoleChange = async (userId, newRole) => {
    59→    const success = await updateUserRole(userId, newRole);
    60→    if (success) {
    61→      const userList = await getAllUsers();
    62→      setUsers(userList);
    63→    } else {
    64→      alert("Erreur lors de la mise à jour du rôle de l'utilisateur.");
    65→    }
    66→  };
    67→
    68→  const handleCreateUser = async (e) => {
    69→    e.preventDefault();
    70→    if (!newUserEmail || !newUserPassword) {
    71→      alert("Veuillez saisir une adresse e-mail et un mot de passe.");
    72→      return;
    73→    }
    74→    const { success, error } = await registerUser(newUserEmail, newUserPassword);
    75→    if (success) {
    76→      alert("Utilisateur créé avec succès !");
    77→      setNewUserEmail('');
    78→      setNewUserPassword('');
    79→      // Refresh the user list
    80→      const userList = await getAllUsers();
    81→      setUsers(userList);
    82→    } else {
    83→      alert(`Erreur lors de la création de l'utilisateur : ${error.message}`);
    84→    }
    85→  };
    86→
    87→  const handleDeleteUser = async (userId) => {
    88→    if (window.confirm("Êtes-vous sûr de vouloir supprimer cet utilisateur ? Cette action est irréversible.")) {
    89→      const { success, error } = await deleteUser(userId);
    90→      if (success) {
    91→        alert("Utilisateur supprimé avec succès !");
    92→        const userList = await getAllUsers();
    93→        setUsers(userList);
    94→      } else {
    95→        alert(`Erreur lors de la suppression de l'utilisateur : ${error.message}`);
    96→      }
    97→    }
    98→  };
    99→
   100→  const handleChangePassword = async (userId) => {
   101→    const newPassword = prompt("Veuillez saisir le nouveau mot de passe :");
   102→    if (newPassword) {
   103→      const { success, error } = await changeUserPassword(userId, newPassword);
   104→      if (success) {
   105→        alert("Mot de passe modifié avec succès !");
   106→      } else {
   107→        alert(`Erreur lors de la modification du mot de passe : ${error.message}`);
   108→      }
   109→    }
   110→  };
   111→
   112→  const handleClearAnonymousUsers = async () => {
   113→    if (!confirm("Êtes-vous sûr de vouloir supprimer tous les utilisateurs anonymes ? Cette action est irréversible.")) {
   114→      return;
   115→    }
   116→    setIsClearingAnonymousUsers(true);
   117→    try {
   118→      const user = getAuth().currentUser;
   119→      if (!user) {
   120→        alert("Vous devez être connecté pour effectuer cette action.");
   121→        return;
   122→      }
   123→      const idToken = await user.getIdToken();
   124→
   125→      const response = await fetch(`${cloudFunctionsBaseUrl}/clearAnonymousUsers`, {
   126→        method: 'POST',
   127→        headers: {
   128→          'Content-Type': 'application/json',
   129→          'Authorization': `Bearer ${idToken}`,
   130→        },
   131→      });
   132→
   133→      if (!response.ok) {
   134→        const errorData = await response.json();
   135→        throw new Error(errorData.message || 'Erreur lors de la suppression des utilisateurs anonymes.');
   136→      }
   137→
   138→      const result = await response.json();
   139→      alert(result.message);
   140→    } catch (error) {
   141→      console.error("Erreur lors de la suppression des utilisateurs anonymes:", error);
   142→      alert(`Erreur: ${error.message}`);
   143→    } finally {
   144→      setIsClearingAnonymousUsers(false);
   145→    }
   146→  };
   147→
   148→  // Removed handlePopulateProducts, handleClearProducts, handlePopulateDishes functions
   149→
   150→  return (
   151→    <Card title="Configuration Système" titleIcon={<Settings />}>
   152→      <div className="flex items-end gap-4 mb-4">
   153→        <div className="flex-1">
   154→          <label className="block text-gray-500 text-[9px] uppercase mb-1">Nombre de tables en salle</label>
   155→          <input 
   156→            type="number" 
   157→            value={tableCount}
   158→            onChange={(e) => setTableCount(e.target.value)}
   159→            className="w-full bg-black border border-gray-800 rounded p-2 text-white outline-none focus:border-mictlan-gold"
   160→            min="1"
   161→            max="50"
   162→          />
   163→        </div>
   164→
   165→        <button 
   166→          onClick={handleReset}
   167→          disabled={isUpdating}
   168→          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
   169→        >
   170→          <RefreshCw className={`w-3 h-3 ${isUpdating ? 'animate-spin' : ''}`} />
   171→          {isUpdating ? 'Mise à jour...' : 'Réinitialiser Salle'}
   172→        </button>
   173→        <button 
   174→          onClick={handleEmpty}
   175→          disabled={isEmptying}
   176→          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
   177→        >
   178→          <Trash2 className={`w-3 h-3 ${isEmptying ? 'animate-spin' : ''}`} />
   179→          {isEmptying ? 'Vidage...' : 'Vider DB'}
   180→        </button>
   181→        <button 
   182→          onClick={handleClearAnonymousUsers}
   183→          disabled={isClearingAnonymousUsers}
   184→          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
   185→        >
   186→          <Users className={`w-3 h-3 ${isClearingAnonymousUsers ? 'animate-spin' : ''}`} />
   187→          {isClearingAnonymousUsers ? 'Suppression...' : 'Supprimer Anonymes'}
   188→        </button>
   189→      </div>
   190→      <p className="text-[8px] text-gray-600 mt-2 italic font-mono uppercase">
   191→        * Réinitialiser Salle : Efface toutes les données actuelles pour générer {tableCount} tables. Vider DB : Supprime toutes les données des collections connues (tables, inventory, logs, users). Supprimer Anonymes : Supprime les documents des utilisateurs sans adresse e-mail. Pour vider toutes les collections inconnues, exécutez `npm run empty-db` or `node empty-db.cjs` dans un terminal.
   192→      </p>
   193→
   194→            {/* ... (previous JSX) */}
   195→      <div className="mt-4">
   196→        <h3 className="text-lg font-bold mb-2 text-white">Gestion des Utilisateurs</h3>
   197→        <ul className="space-y-2">
   198→          {users.map(user => (
