   242→            jul: '07', aug: '08', sep: '09', oct: '10', nov: '11', dec: '12'
   243→          };
   244→          const month = monthMap[monthStr.toLowerCase()];
   245→          detectedDate = `${year}-${month}-${day}`;
   246→        }
   247→        break;
   248→      }
